data.script:
// Bulk Email Facturen v3 - Sales Invoice List View
// Auto-detectie: Credit / Vaste prijs (Aangenomen werk) / Uren
var _si_settings = frappe.listview_settings['Sales Invoice'] || {};
frappe.listview_settings['Sales Invoice'] = _si_settings;
var _si_orig_onload = _si_settings.onload;

// =====================================================================
// Extra velden laden voor lijstweergave
// =====================================================================
_si_settings.add_fields = ['posting_date', 'outstanding_amount', 'due_date', 'custom_date_paid'];

// =====================================================================
// Kleur-indicators voor kolommen
// =====================================================================
_si_settings.formatters = Object.assign({}, _si_settings.formatters || {}, {
    custom_days_open: function(value, df, doc) {
        if (!doc || !doc.posting_date || doc.docstatus !== 1) return '';
        // Betaalde factuur: toon dagen tot betaling in groen
        if (doc.outstanding_amount <= 0 && doc.custom_date_paid) {
            var days_to_pay = frappe.datetime.get_diff(doc.custom_date_paid, doc.posting_date);
            if (days_to_pay < 0) days_to_pay = 0;
            return '<span class="indicator-pill green">' + days_to_pay + 'd</span>';
        }
        if (doc.outstanding_amount <= 0) return '';
        var today = frappe.datetime.get_today();
        var days = frappe.datetime.get_diff(today, doc.posting_date);
        if (days <= 0) return '';
        var due_days = doc.due_date ? frappe.datetime.get_diff(today, doc.due_date) : 0;
        if (due_days > 30) return '<span class="indicator-pill red">' + days + 'd</span>';
        if (due_days > 0) return '<span class="indicator-pill orange">' + days + 'd</span>';
        return '<span class="indicator-pill blue">' + days + 'd</span>';
    },
    custom_email_status: function(value) {
        if (value === 'Verstuurd') {
            return '<span class="indicator-pill green">Verstuurd</span>';
        } else if (value === 'Herinnering 1') {
            return '<span class="indicator-pill orange">Herinnering 1</span>';
        }
        return '';
    }
});

// =====================================================================
// Onload: bulk email knoppen + dagen open kolom
// =====================================================================
_si_settings.onload = function(listview) {
    if (_si_orig_onload) _si_orig_onload.call(this, listview);
    if (!listview._bulk_email_added) {
        listview._bulk_email_added = true;
        listview.page.add_action_item(__('Bulk Email Facturen'), function() {
            _be_start(listview);
        });
        listview.page.add_action_item(__('Bulk Email Herinneringen'), function() {
            _bh_start(listview);
        });
    }

    // Dagen Open kolom: bereken na elke render
    if (!listview._days_open_hooked) {
        listview._days_open_hooked = true;
        var orig_render = listview.render.bind(listview);
        listview.render = function() {
            orig_render();
            _si_update_days_open(listview);
        };
        // Eerste keer ook uitvoeren
        setTimeout(function() { _si_update_days_open(listview); }, 300);
    }
};

function _si_update_days_open(listview) {
    var today = frappe.datetime.get_today();
    listview.$result.find('.list-row-container .list-row').each(function() {
        var $row = $(this);
        var $cell = $row.find('.list-row-col[data-field="custom_days_open"] .static-area, .list-row-col[data-field="custom_days_open"] .field-area');
        if (!$cell.length) {
            // Probeer ook via kolomindex
            $row.find('.list-row-col').each(function() {
                if ($(this).data('field') === 'custom_days_open') {
                    $cell = $(this).find('.static-area, .field-area');
                }
            });
        }
        if (!$cell.length) return;

        var name = $row.find('.level-left .list-row--col .ellipsis a').attr('href');
        if (!name) return;
        name = name.split('/').pop();

        // Zoek de data in de geladen records
        var doc = (listview.data || []).find(function(d) { return d.name === name; });
        if (!doc) return;

        if (!doc.posting_date || doc.docstatus !== 1) {
            $cell.html('');
            return;
        }

        // Betaalde factuur: toon dagen tot betaling in groen
        if (doc.outstanding_amount <= 0 && doc.custom_date_paid) {
            var days_to_pay = frappe.datetime.get_diff(doc.custom_date_paid, doc.posting_date);
            if (days_to_pay < 0) days_to_pay = 0;
            $cell.html('<span class="indicator-pill green">' + days_to_pay + 'd</span>');
            return;
        }

        if (doc.outstanding_amount <= 0) { $cell.html(''); return; }

        var days = frappe.datetime.get_diff(today, doc.posting_date);
        if (days <= 0) { $cell.html(''); return; }

        var due_days = doc.due_date ? frappe.datetime.get_diff(today, doc.due_date) : 0;
        var pill;
        if (due_days > 30) {
            pill = '<span class="indicator-pill red">' + days + 'd</span>';
        } else if (due_days > 0) {
            pill = '<span class="indicator-pill orange">' + days + 'd</span>';
        } else {
            pill = '<span class="indicator-pill blue">' + days + 'd</span>';
        }
        $cell.html(pill);
    });
}

// =====================================================================
// Stap 1: Selectie valideren + gegevens ophalen + type detectie
// =====================================================================
async function _be_start(listview) {
    var checked = listview.get_checked_items();
    if (!checked.length) {
        frappe.msgprint(__('Selecteer eerst een of meer facturen.'));
        return;
    }

    var names = checked.filter(function(d) { return d.docstatus === 1; }).map(function(d) { return d.name; });
    var skipped_count = checked.length - names.length;

    if (!names.length) {
        frappe.msgprint(__('Alleen ingediende (submitted) facturen kunnen gemaild worden.'));
        return;
    }

    frappe.dom.freeze(__('Factuurgegevens, items en e-mailadressen ophalen...'));

    var invoices = [];
    try {
        // Haal facturen op
        var inv_list = await frappe.xcall('frappe.client.get_list', {
            doctype: 'Sales Invoice',
            filters: { name: ['in', names] },
            fields: ['name', 'is_return', 'return_against', 'customer', 'customer_name', 'contact_email', 'contact_display'],
            limit_page_length: 0
        });

        // Detecteer facturen met "Aangenomen werk" via parent doctype filter (geen directe child table query)
        var aangenomen_result = await frappe.xcall('frappe.client.get_list', {
            doctype: 'Sales Invoice',
            filters: [['Sales Invoice Item', 'item_code', 'like', '%Aangenomen werk%'], ['name', 'in', names]],
            fields: ['name'],
            limit_page_length: 0
        });
        var aangenomen_set = {};
        for (var k = 0; k < aangenomen_result.length; k++) {
            aangenomen_set[aangenomen_result[k].name] = true;
        }

        for (var ii = 0; ii < inv_list.length; ii++) {
            var inv = inv_list[ii];
            var email = inv.contact_email || '';
            if (!email) {
                email = await _be_lookup_email(inv.customer);
            }

            // Type-detectie
            var is_credit = !!(inv.is_return || inv.return_against);
            var invoice_type, print_format;

            if (is_credit) {
                invoice_type = 'credit';
                print_format = '3BM Credit Nieuw';
            } else {
                // Check of factuur "Aangenomen werk" items bevat
                var has_aangenomen = !!aangenomen_set[inv.name];

                if (has_aangenomen) {
                    invoice_type = 'vaste_prijs';
                    print_format = '3BM Factuur Nieuw';
                } else {
                    invoice_type = 'uren';
                    print_format = '3BM Factuur+Urenstaat Nieuw';
                }
            }

            invoices.push({
                name: inv.name,
                customer: inv.customer,
                customer_name: inv.customer_name || inv.customer,
                email: email,
                is_return: is_credit,
                invoice_type: invoice_type,
                print_format: print_format,
                contact_display: inv.contact_display || ''
            });
        }

        // Sorteer: credits onderaan, dan op naam
        invoices.sort(function(a, b) {
            var type_order = { vaste_prijs: 0, uren: 1, credit: 2 };
            var diff = (type_order[a.invoice_type] || 0) - (type_order[b.invoice_type] || 0);
            if (diff !== 0) return diff;
            return a.name.localeCompare(b.name);
        });

    } catch(e) {
        frappe.dom.unfreeze();
        frappe.msgprint(__('Fout bij ophalen: ') + (e.message || ''));
        return;
    }
    frappe.dom.unfreeze();

    _be_review_dialog(invoices, skipped_count);
}

// =====================================================================
// Stap 2: Review-dialoog met bewerkbare tabel
// =====================================================================
function _be_review_dialog(invoices, skipped_count) {
    var pf_options = [
        { value: '3BM Factuur Nieuw', label: 'Factuur' },
        { value: '3BM Factuur+Urenstaat Nieuw', label: 'Factuur + Urenstaat' },
        { value: '3BM Credit Nieuw', label: 'Creditnota' }
    ];

    var type_pills = {
        vaste_prijs: '<span class="indicator-pill green">Vaste prijs</span>',
        uren: '<span class="indicator-pill blue">Uren</span>',
        credit: '<span class="indicator-pill red">Credit</span>'
    };

    var rows = '';
    for (var i = 0; i < invoices.length; i++) {
        var inv = invoices[i];
        var opts = '';
        for (var j = 0; j < pf_options.length; j++) {
            var pf = pf_options[j];
            opts += '<option value="' + pf.value + '"' + (pf.value === inv.print_format ? ' selected' : '') + '>' + pf.label + '</option>';
        }

        var type_pill = type_pills[inv.invoice_type] || '';

        // Klikbare klantnaam met link naar Customer record
        var customer_link = '<a href="/app/customer/' + encodeURIComponent(inv.customer) + '" target="_blank" title="Open klantpagina">'
            + frappe.utils.escape_html(inv.customer_name) + '</a>';

        // Email veld met link naar klant bij ontbrekend emailadres
        var email_style = !inv.email ? 'border:1px solid var(--red-500);background:var(--red-50);' : '';
        var email_extra = '';
        if (!inv.email) {
            email_extra = ' <a href="/app/customer/' + encodeURIComponent(inv.customer) + '" target="_blank" '
                + 'title="Open klantpagina om e-mail toe te voegen" '
                + 'style="color:var(--red-500);font-size:16px;vertical-align:middle;">'
                + '<svg class="icon icon-sm" style="width:14px;height:14px;"><use href="#icon-link-url"></use></svg>'
                + '</a>';
        }

        rows += '<tr data-idx="' + i + '">'
            + '<td class="text-center"><input type="checkbox" class="be-chk" data-idx="' + i + '" checked></td>'
            + '<td style="white-space:nowrap;"><strong>' + frappe.utils.escape_html(inv.name) + '</strong></td>'
            + '<td>' + type_pill + '</td>'
            + '<td>' + customer_link + '</td>'
            + '<td><div style="display:flex;align-items:center;gap:4px;"><input type="email" class="form-control form-control-sm be-email" data-idx="' + i + '" value="' + frappe.utils.escape_html(inv.email) + '" style="min-width:180px;' + email_style + '" placeholder="email@voorbeeld.nl">' + email_extra + '</div></td>'
            + '<td><select class="form-control form-control-sm be-fmt" data-idx="' + i + '">' + opts + '</select></td>'
            + '</tr>';
    }

    var warnings = '';
    var no_email_cnt = invoices.filter(function(x) { return !x.email; }).length;
    if (no_email_cnt) {
        warnings += '<div class="alert alert-warning mb-2">' + no_email_cnt + ' factuur/facturen zonder e-mailadres (rood gemarkeerd)</div>';
    }
    if (skipped_count) {
        warnings += '<div class="alert alert-info mb-2">' + skipped_count + ' niet-submitted facturen overgeslagen</div>';
    }

    var html = warnings
        + '<div style="max-height:450px; overflow-y:auto;">'
        + '<table class="table table-bordered table-sm table-hover" style="margin-bottom:0;">'
        + '<thead style="position:sticky;top:0;background:#f7f7f7;z-index:1;">'
        + '<tr>'
        + '<th style="width:35px" class="text-center"><input type="checkbox" id="be-all" checked></th>'
        + '<th>Factuurnr</th>'
        + '<th style="width:100px">Type</th>'
        + '<th>Klant</th>'
        + '<th>Email</th>'
        + '<th style="min-width:160px">Bijlage</th>'
        + '</tr>'
        + '</thead>'
        + '<tbody>' + rows + '</tbody>'
        + '</table></div>';

    var primary_fn = function() {
        var to_send = [];
        d.$wrapper.find('.be-chk:checked').each(function() {
            var idx = $(this).data('idx');
            var inv = invoices[idx];
            var email = d.$wrapper.find('.be-email[data-idx="' + idx + '"]').val().trim();
            var fmt = d.$wrapper.find('.be-fmt[data-idx="' + idx + '"]').val();
            if (email) {
                to_send.push({
                    name: inv.name,
                    email: email,
                    print_format: fmt,
                    is_return: inv.is_return,
                    contact_display: inv.contact_display
                });
            }
        });

        if (!to_send.length) {
            frappe.msgprint(__('Geen facturen met geldig emailadres geselecteerd.'));
            return;
        }

        d.hide();
        _be_send(to_send);
    };

    var d = new frappe.ui.Dialog({
        title: __('Bulk Email Facturen \u2014 Controleer & Verstuur'),
        fields: [
            { fieldtype: 'HTML', fieldname: 'review_table', options: html }
        ],
        size: 'extra-large',
        primary_action_label: __('Verstuur ' + invoices.length + ' Email(s)'),
        primary_action: primary_fn
    });

    d.$wrapper.on('change', '#be-all', function() {
        d.$wrapper.find('.be-chk').prop('checked', $(this).is(':checked'));
        _update_btn();
    });

    d.$wrapper.on('change', '.be-chk', function() {
        var total = d.$wrapper.find('.be-chk').length;
        var checked = d.$wrapper.find('.be-chk:checked').length;
        d.$wrapper.find('#be-all').prop('checked', checked === total);
        _update_btn();
    });

    function _update_btn() {
        var n = d.$wrapper.find('.be-chk:checked').length;
        d.get_primary_btn().text(__('Verstuur ' + n + ' Email(s)'));
    }

    d.show();
}

// =====================================================================
// Stap 3: Emails versturen
// =====================================================================
async function _be_send(items) {
    var total = items.length;
    frappe.show_progress(__('Bulk Email'), 0, total, __('Voorbereiden...'));

    var signature = '';
    try {
        var ea = await frappe.xcall('frappe.client.get_value', {
            doctype: 'Email Account',
            filters: { email_id: frappe.session.user_email },
            fieldname: ['name', 'signature']
        });
        if (ea && ea.signature) signature = '<br><br>' + ea.signature;
    } catch(e) { /* ignore */ }

    var results = { success: [], skipped: [], failed: [] };

    for (var i = 0; i < items.length; i++) {
        var item = items[i];
        frappe.show_progress(__('Bulk Email'), i, total, item.name + ' (' + (i + 1) + '/' + total + ')');

        try {
            var doc = await frappe.xcall('frappe.client.get', {
                doctype: 'Sales Invoice',
                name: item.name
            });

            var template_name = item.is_return ? 'Credit-template' : 'Factuur template';

            var tmpl = await frappe.xcall(
                'frappe.email.doctype.email_template.email_template.get_email_template',
                { template_name: template_name, doc: doc }
            );
            if (!tmpl) {
                results.failed.push({ name: item.name, reason: 'Template niet gevonden' });
                continue;
            }

            var message = tmpl.message || '';
            if (item.contact_display) {
                var firstName = item.contact_display.split(' ')[0];
                message = message.replace('Geachte heer/mevrouw,', 'Geachte ' + firstName + ',');
            }
            if (signature) message += signature;

            await frappe.xcall('frappe.core.doctype.communication.email.make', {
                recipients: item.email,
                subject: tmpl.subject || item.name,
                content: message,
                doctype: 'Sales Invoice',
                name: item.name,
                send_email: 1,
                print_format: item.print_format,
                print_letterhead: 1,
                sender: frappe.session.user_email,
                send_me_a_copy: 0
            });

            // Update email datum
            await frappe.xcall('frappe.client.set_value', {
                doctype: 'Sales Invoice',
                name: item.name,
                fieldname: { custom_email_status: 'Verstuurd', custom_date_email: frappe.datetime.get_today() }
            });

            results.success.push(item.name);

        } catch(err) {
            console.error('Bulk email error:', item.name, err);
            results.failed.push({ name: item.name, reason: err.message || 'Onbekende fout' });
        }
    }

    frappe.show_progress(__('Bulk Email'), total, total, __('Klaar!'));
    setTimeout(function() { frappe.hide_progress(); }, 500);
    _be_show_results(results);
}

// =====================================================================
// Stap 4: Resultaat tonen
// =====================================================================
function _be_show_results(results) {
    var html = '';
    if (results.success.length) {
        html += '<div class="alert alert-success"><strong>' + results.success.length + ' email(s) succesvol verstuurd</strong><br><small>' + results.success.join(', ') + '</small></div>';
    }
    if (results.skipped.length) {
        html += '<div class="alert alert-warning"><strong>' + results.skipped.length + ' overgeslagen</strong><br>';
        results.skipped.forEach(function(s) { html += '<small>' + s.name + ': ' + s.reason + '</small><br>'; });
        html += '</div>';
    }
    if (results.failed.length) {
        html += '<div class="alert alert-danger"><strong>' + results.failed.length + ' mislukt</strong><br>';
        results.failed.forEach(function(f) { html += '<small>' + f.name + ': ' + f.reason + '</small><br>'; });
        html += '</div>';
    }
    frappe.msgprint({ title: __('Bulk Email Resultaat'), message: html, wide: true });
}

// =====================================================================
// Email lookup helper
// =====================================================================
async function _be_lookup_email(customer) {
    if (!customer) return '';
    try {
        var cust = await frappe.xcall('frappe.client.get_value', {
            doctype: 'Customer',
            filters: { name: customer },
            fieldname: ['customer_primary_contact', 'email_id']
        });
        if (!cust) return '';

        if (cust.customer_primary_contact) {
            var c = await frappe.xcall('frappe.client.get_value', {
                doctype: 'Contact',
                filters: { name: cust.customer_primary_contact },
                fieldname: 'email_id'
            });
            if (c && c.email_id) return c.email_id;
        }
        if (cust.email_id) return cust.email_id;

        var links = await frappe.xcall('frappe.client.get_list', {
            doctype: 'Dynamic Link',
            filters: { parenttype: 'Contact', link_doctype: 'Customer', link_name: customer },
            fields: ['parent'],
            limit_page_length: 1,
            order_by: 'creation asc'
        });
        if (links && links.length) {
            var fb = await frappe.xcall('frappe.client.get_value', {
                doctype: 'Contact',
                filters: { name: links[0].parent },
                fieldname: 'email_id'
            });
            if (fb && fb.email_id) return fb.email_id;
        }
    } catch(e) { /* ignore */ }
    return '';
}

// =====================================================================
// Helpers: betalingsinfo ophalen voor deelbetalingen
// =====================================================================

async function _bh_get_payment_info(invoice_name) {
    var result = [];
    try {
        var pe_list = await frappe.xcall('frappe.client.get_list', {
            doctype: 'Payment Entry',
            filters: [
                ['Payment Entry Reference', 'reference_name', '=', invoice_name],
                ['docstatus', '=', 1],
                ['payment_type', '=', 'Receive']
            ],
            fields: ['name', 'posting_date'],
            limit_page_length: 10,
            order_by: 'posting_date asc'
        });
        for (var i = 0; i < pe_list.length; i++) {
            var pe_doc = await frappe.xcall('frappe.client.get', {
                doctype: 'Payment Entry',
                name: pe_list[i].name
            });
            var allocated = 0;
            if (pe_doc.references) {
                for (var j = 0; j < pe_doc.references.length; j++) {
                    if (pe_doc.references[j].reference_name === invoice_name) {
                        allocated = pe_doc.references[j].allocated_amount;
                        break;
                    }
                }
            }
            if (allocated > 0) {
                result.push({
                    date: pe_list[i].posting_date,
                    amount: allocated
                });
            }
        }
    } catch(e) {
        console.log('Payment info lookup failed:', e);
    }
    return result;
}

function _bh_partial_payment_msg(doc, payments) {
    var name = doc.contact_display || '';
    var greeting;
    if (name) {
        greeting = 'Geachte heer/mevrouw ' + name + ',';
    } else {
        greeting = 'Geachte heer/mevrouw,';
    }

    var html = '<p>' + greeting + '</p>';

    html += '<p>Wij willen u erop wijzen dat de betaling van factuur <strong>' + doc.name
        + '</strong> nog niet volledig is voldaan. Het oorspronkelijke factuurbedrag bedraagt <strong>'
        + format_currency(doc.grand_total, 'EUR') + '</strong> (inclusief BTW).</p>';

    html += '<p>';
    if (payments.length > 0) {
        for (var i = 0; i < payments.length; i++) {
            var p = payments[i];
            html += 'Op <strong>' + frappe.datetime.str_to_user(p.date) + '</strong> hebben wij een deelbetaling van <strong>'
                + format_currency(p.amount, 'EUR') + '</strong> ontvangen, waarvoor dank.<br>';
        }
    } else {
        var paid = doc.grand_total - doc.outstanding_amount;
        html += 'Wij hebben een deelbetaling van <strong>' + format_currency(paid, 'EUR')
            + '</strong> ontvangen, waarvoor dank.<br>';
    }
    html += 'Het resterende openstaande bedrag is <strong>' + format_currency(doc.outstanding_amount, 'EUR') + '</strong>.</p>';

    html += '<p>Wij verzoeken u vriendelijk het resterende bedrag van <strong>'
        + format_currency(doc.outstanding_amount, 'EUR')
        + '</strong> zo spoedig mogelijk, doch uiterlijk binnen 7 dagen, te voldoen op rekeningnummer [IBAN] onder vermelding van factuurnummer '
        + doc.name + '.</p>';

    return html;
}

// =====================================================================
// BULK EMAIL HERINNERINGEN
// =====================================================================

// =====================================================================
// Herinnering Stap 1: Selectie valideren + gegevens ophalen
// =====================================================================
async function _bh_start(listview) {
    var checked = listview.get_checked_items();
    if (!checked.length) {
        frappe.msgprint(__('Selecteer eerst een of meer facturen.'));
        return;
    }

    // Alleen submitted facturen met openstaand bedrag
    var names = checked.filter(function(d) { return d.docstatus === 1; }).map(function(d) { return d.name; });
    var skipped_draft = checked.length - names.length;

    if (!names.length) {
        frappe.msgprint(__('Alleen ingediende (submitted) facturen kunnen een herinnering krijgen.'));
        return;
    }

    frappe.dom.freeze(__('Factuurgegevens en e-mailadressen ophalen...'));

    var invoices = [];
    try {
        var inv_list = await frappe.xcall('frappe.client.get_list', {
            doctype: 'Sales Invoice',
            filters: { name: ['in', names] },
            fields: ['name', 'customer', 'customer_name', 'contact_email', 'contact_display',
                     'grand_total', 'outstanding_amount', 'posting_date', 'due_date', 'company',
                     'is_return', 'return_against'],
            limit_page_length: 0
        });

        var skipped_paid = 0;
        var skipped_credit = 0;
        for (var ii = 0; ii < inv_list.length; ii++) {
            var inv = inv_list[ii];

            // Sla betaalde facturen en credit-nota's over
            if (inv.outstanding_amount <= 0) { skipped_paid++; continue; }
            if (inv.is_return || inv.return_against) { skipped_credit++; continue; }

            var email = inv.contact_email || '';
            if (!email) {
                email = await _be_lookup_email(inv.customer);
            }

            var today = frappe.datetime.get_today();
            var days_open = frappe.datetime.get_diff(today, inv.posting_date);

            invoices.push({
                name: inv.name,
                customer: inv.customer,
                customer_name: inv.customer_name || inv.customer,
                email: email,
                grand_total: inv.grand_total,
                outstanding_amount: inv.outstanding_amount,
                posting_date: inv.posting_date,
                due_date: inv.due_date,
                days_open: days_open,
                company: inv.company,
                contact_display: inv.contact_display || ''
            });
        }

        invoices.sort(function(a, b) { return b.days_open - a.days_open; });

    } catch(e) {
        frappe.dom.unfreeze();
        frappe.msgprint(__('Fout bij ophalen: ') + (e.message || ''));
        return;
    }
    frappe.dom.unfreeze();

    if (!invoices.length) {
        frappe.msgprint(__('Geen openstaande facturen gevonden in de selectie.'));
        return;
    }

    _bh_review_dialog(invoices, skipped_draft, skipped_paid, skipped_credit);
}

// =====================================================================
// Herinnering Stap 2: Review-dialoog met preview
// =====================================================================
function _bh_review_dialog(invoices, skipped_draft, skipped_paid, skipped_credit) {
    var rows = '';
    for (var i = 0; i < invoices.length; i++) {
        var inv = invoices[i];

        var customer_link = '<a href="/app/customer/' + encodeURIComponent(inv.customer) + '" target="_blank">'
            + frappe.utils.escape_html(inv.customer_name) + '</a>';

        var email_style = !inv.email ? 'border:1px solid var(--red-500);background:var(--red-50);' : '';
        var email_extra = '';
        if (!inv.email) {
            email_extra = ' <a href="/app/customer/' + encodeURIComponent(inv.customer) + '" target="_blank" '
                + 'style="color:var(--red-500);font-size:16px;vertical-align:middle;" title="Open klantpagina">'
                + '<svg class="icon icon-sm" style="width:14px;height:14px;"><use href="#icon-link-url"></use></svg>'
                + '</a>';
        }

        var days_pill = inv.days_open > 60
            ? '<span class="indicator-pill red">' + inv.days_open + 'd</span>'
            : '<span class="indicator-pill orange">' + inv.days_open + 'd</span>';

        var is_partial = inv.outstanding_amount < inv.grand_total;
        var amount_display = format_currency(inv.outstanding_amount, 'EUR');
        if (is_partial) {
            amount_display += ' <span class="indicator-pill yellow" style="font-size:10px;">deelbetaling</span>';
        }

        rows += '<tr data-idx="' + i + '">'
            + '<td class="text-center"><input type="checkbox" class="bh-chk" data-idx="' + i + '" checked></td>'
            + '<td style="white-space:nowrap;"><strong>' + frappe.utils.escape_html(inv.name) + '</strong></td>'
            + '<td>' + customer_link + '</td>'
            + '<td class="text-right" style="white-space:nowrap;">' + amount_display + '</td>'
            + '<td class="text-center">' + days_pill + '</td>'
            + '<td><div style="display:flex;align-items:center;gap:4px;"><input type="email" class="form-control form-control-sm bh-email" data-idx="' + i + '" value="' + frappe.utils.escape_html(inv.email) + '" style="min-width:180px;' + email_style + '" placeholder="email@voorbeeld.nl">' + email_extra + '</div></td>'
            + '<td class="text-center"><button class="btn btn-xs btn-default bh-preview-btn" data-idx="' + i + '" title="Preview email"><svg class="icon icon-sm"><use href="#icon-eye"></use></svg></button></td>'
            + '</tr>';
    }

    var warnings = '';
    var no_email_cnt = invoices.filter(function(x) { return !x.email; }).length;
    if (no_email_cnt) {
        warnings += '<div class="alert alert-warning mb-2">' + no_email_cnt + ' factuur/facturen zonder e-mailadres (rood gemarkeerd)</div>';
    }
    if (skipped_draft) {
        warnings += '<div class="alert alert-info mb-2">' + skipped_draft + ' niet-submitted facturen overgeslagen</div>';
    }
    if (skipped_paid) {
        warnings += '<div class="alert alert-info mb-2">' + skipped_paid + ' reeds betaalde facturen overgeslagen</div>';
    }
    if (skipped_credit) {
        warnings += '<div class="alert alert-info mb-2">' + skipped_credit + ' credit-nota\'s overgeslagen</div>';
    }

    var html = warnings
        + '<div style="max-height:450px; overflow-y:auto;">'
        + '<table class="table table-bordered table-sm table-hover" style="margin-bottom:0;">'
        + '<thead style="position:sticky;top:0;background:#f7f7f7;z-index:1;">'
        + '<tr>'
        + '<th style="width:35px" class="text-center"><input type="checkbox" id="bh-all" checked></th>'
        + '<th>Factuurnr</th>'
        + '<th>Klant</th>'
        + '<th class="text-right">Openstaand</th>'
        + '<th class="text-center" style="width:70px">Open</th>'
        + '<th>Email</th>'
        + '<th style="width:50px" class="text-center">Preview</th>'
        + '</tr>'
        + '</thead>'
        + '<tbody>' + rows + '</tbody>'
        + '</table></div>';

    var primary_fn = function() {
        var to_send = [];
        d.$wrapper.find('.bh-chk:checked').each(function() {
            var idx = $(this).data('idx');
            var inv = invoices[idx];
            var email = d.$wrapper.find('.bh-email[data-idx="' + idx + '"]').val().trim();
            if (email) {
                to_send.push({
                    name: inv.name,
                    email: email,
                    contact_display: inv.contact_display,
                    company: inv.company
                });
            }
        });

        if (!to_send.length) {
            frappe.msgprint(__('Geen facturen met geldig emailadres geselecteerd.'));
            return;
        }

        d.hide();
        _bh_send(to_send);
    };

    var d = new frappe.ui.Dialog({
        title: __('Bulk Email Herinneringen \u2014 Controleer & Verstuur'),
        fields: [
            { fieldtype: 'HTML', fieldname: 'review_table', options: html }
        ],
        size: 'extra-large',
        primary_action_label: __('Verstuur ' + invoices.length + ' Herinnering(en)'),
        primary_action: primary_fn
    });

    // Select all / deselect all
    d.$wrapper.on('change', '#bh-all', function() {
        d.$wrapper.find('.bh-chk').prop('checked', $(this).is(':checked'));
        _bh_update_btn();
    });

    d.$wrapper.on('change', '.bh-chk', function() {
        var total = d.$wrapper.find('.bh-chk').length;
        var checked = d.$wrapper.find('.bh-chk:checked').length;
        d.$wrapper.find('#bh-all').prop('checked', checked === total);
        _bh_update_btn();
    });

    function _bh_update_btn() {
        var n = d.$wrapper.find('.bh-chk:checked').length;
        d.get_primary_btn().text(__('Verstuur ' + n + ' Herinnering(en)'));
    }

    // Preview knop
    d.$wrapper.on('click', '.bh-preview-btn', async function() {
        var idx = $(this).data('idx');
        var inv = invoices[idx];
        $(this).prop('disabled', true).html('<span class="spinner-border spinner-border-sm"></span>');

        try {
            var doc = await frappe.xcall('frappe.client.get', {
                doctype: 'Sales Invoice',
                name: inv.name
            });

            var tmpl = await frappe.xcall(
                'frappe.email.doctype.email_template.email_template.get_email_template',
                { template_name: 'Betalingsherinnering 1', doc: doc }
            );

            if (!tmpl) {
                frappe.msgprint(__('Template "Betalingsherinnering 1" niet gevonden.'));
                return;
            }

            var subject = tmpl.subject || '';
            var message;
            var paid_amount = parseFloat(doc.grand_total) - parseFloat(doc.outstanding_amount);

            if (paid_amount > 1) {
                // Deelbetaling: haal betalingsinfo op en bouw aangepaste tekst
                var payments = await _bh_get_payment_info(doc.name);
                message = _bh_partial_payment_msg(doc, payments);
            } else {
                // Volledig onbetaald: gebruik template
                message = tmpl.message || '';
            }

            var preview_html = '<div style="margin-bottom:12px;">'
                + '<strong>Aan:</strong> ' + frappe.utils.escape_html(inv.email || '(geen email)') + '<br>'
                + '<strong>Onderwerp:</strong> ' + frappe.utils.escape_html(subject)
                + '</div>'
                + '<hr>'
                + '<div style="padding:16px;background:#fff;border:1px solid #d1d8dd;border-radius:4px;font-family:Arial,sans-serif;font-size:13px;">'
                + message
                + '</div>';

            var pd = new frappe.ui.Dialog({
                title: __('Preview: Herinnering ' + inv.name),
                fields: [
                    { fieldtype: 'HTML', fieldname: 'preview_content', options: preview_html }
                ],
                size: 'large'
            });
            pd.show();

        } catch(err) {
            frappe.msgprint(__('Fout bij preview: ') + (err.message || ''));
        } finally {
            $(this).prop('disabled', false).html('<svg class="icon icon-sm"><use href="#icon-eye"></use></svg>');
        }
    });

    d.show();
}

// =====================================================================
// Herinnering Stap 3: Emails versturen + status bijwerken
// =====================================================================
async function _bh_send(items) {
    var total = items.length;
    frappe.show_progress(__('Bulk Herinneringen'), 0, total, __('Voorbereiden...'));

    var signature = '';
    try {
        var ea = await frappe.xcall('frappe.client.get_value', {
            doctype: 'Email Account',
            filters: { email_id: frappe.session.user_email },
            fieldname: ['name', 'signature']
        });
        if (ea && ea.signature) signature = '<br><br>' + ea.signature;
    } catch(e) { /* ignore */ }

    var results = { success: [], failed: [] };

    for (var i = 0; i < items.length; i++) {
        var item = items[i];
        frappe.show_progress(__('Bulk Herinneringen'), i, total, item.name + ' (' + (i + 1) + '/' + total + ')');

        try {
            var doc = await frappe.xcall('frappe.client.get', {
                doctype: 'Sales Invoice',
                name: item.name
            });

            var tmpl = await frappe.xcall(
                'frappe.email.doctype.email_template.email_template.get_email_template',
                { template_name: 'Betalingsherinnering 1', doc: doc }
            );
            if (!tmpl) {
                results.failed.push({ name: item.name, reason: 'Template niet gevonden' });
                continue;
            }

            var message;
            var paid_amount = parseFloat(doc.grand_total) - parseFloat(doc.outstanding_amount);

            if (paid_amount > 1) {
                // Deelbetaling: haal betalingsinfo op en bouw aangepaste tekst
                var payments = await _bh_get_payment_info(doc.name);
                message = _bh_partial_payment_msg(doc, payments);
            } else {
                // Volledig onbetaald: gebruik template
                message = tmpl.message || '';
            }

            if (signature) message += signature;

            await frappe.xcall('frappe.core.doctype.communication.email.make', {
                recipients: item.email,
                subject: tmpl.subject || '1e betalingsherinnering ' + item.name,
                content: message,
                doctype: 'Sales Invoice',
                name: item.name,
                send_email: 1,
                print_letterhead: 1,
                sender: frappe.session.user_email,
                send_me_a_copy: 0
            });

            // Update email status + datum
            await frappe.xcall('frappe.client.set_value', {
                doctype: 'Sales Invoice',
                name: item.name,
                fieldname: { custom_email_status: 'Herinnering 1', custom_date_email: frappe.datetime.get_today() }
            });

            results.success.push(item.name);

        } catch(err) {
            console.error('Bulk herinnering error:', item.name, err);
            results.failed.push({ name: item.name, reason: err.message || 'Onbekende fout' });
        }
    }

    frappe.show_progress(__('Bulk Herinneringen'), total, total, __('Klaar!'));
    setTimeout(function() { frappe.hide_progress(); }, 500);
    _be_show_results(results);
}

